+                let completed = Arc::clone(&completed);
+                let closure: Box<
+                    dyn FnOnce(Cx) -> std::pin::Pin<Box<dyn Future<Output = usize> + Send>> + Send,
+                > = Box::new(move |_cx| {
+                    Box::pin(async move {
+                        crate::runtime_compat::sleep(Duration::from_millis(5 * (4 - i) as u64))
+                            .await;
+                        completed.fetch_add(1, Ordering::SeqCst);
+                        i
+                    })
+                });
+                closure
+            })
